1	package agent
2	
3	import (
4		"context"
5		"path/filepath"
6		"strings"
7		"sync"
8		"time"
9	
10		"github.com/DocumentDrivenDX/ddx/internal/workerstatus"
11	)
12	
13	const (
14		providerChildActionTerminated = "terminated"
15		reasonSupersededProviderChild = "superseded_provider_child"
16		reasonRunningPhaseGuard       = "running_phase_non_route_provider_child"
17		reasonAttemptEnded            = "attempt_ended"
18		providerChildCleanupArtifact  = "provider-children.json"
19	)
20	
21	// runningProviderGuardInterval is how often the running-phase guard re-scans
22	// the worker's provider-CLI descendants while an attempt is in flight. Provider
23	// CLIs spawned after route resolution (the dogfooded Codex/Gemini fan-out) are
24	// reaped within one interval instead of surviving until attempt-end cleanup.
25	const runningProviderGuardInterval = 2 * time.Second
26	
27	var providerCLINames = map[string]struct{}{
28		"claude":   {},
29		"codex":    {},
30		"gemini":   {},
31		"opencode": {},
32		"pi":       {},
33	}
34	
35	type providerChildProcess struct {
36		PID       int
37		Provider  string
38		Command   string
39		StartedAt time.Time
40	}
41	
42	type providerChildReapRecord struct {
43		PID        int     `json:"pid"`
44		Provider   string  `json:"provider"`
45		Command    string  `json:"command,omitempty"`
46		AgeSeconds float64 `json:"age_seconds"`
47		Action     string  `json:"action"`
48		Reason     string  `json:"reason"`
49	}
50	
51	type providerChildCleanupReport struct {
52		AttemptID   string                       `json:"attempt_id"`
53		BeadID      string                       `json:"bead_id"`
54		Trigger     string                       `json:"trigger"`
55		ActiveRoute string                       `json:"active_route,omitempty"`
56		ScannedAt   time.Time                    `json:"scanned_at"`
57		Survivors   []workerstatus.ProviderChild `json:"survivors,omitempty"`
58		Reaped      []providerChildReapRecord    `json:"reaped,omitempty"`
59		ScanErr     string                       `json:"scan_error,omitempty"`
60	}
61	
62	var providerChildScanner = func(ctx context.Context, rootPID int, now time.Time) ([]providerChildProcess, error) {
63		return scanProviderChildProcessesImpl(ctx, rootPID, now)
64	}
65	
66	var terminateProviderChild = terminateProviderChildImpl
67	
68	func providerForCommand(cmdline string) string {
69		parts := strings.Fields(strings.TrimSpace(cmdline))
70		if len(parts) == 0 {
71			return ""
72		}
73		base := filepath.Base(parts[0])
74		if _, ok := providerCLINames[base]; ok {
75			return base
76		}
77		// Node-wrapper detection: "node /path/to/provider-cli ..." where argv[0]
78		// is the Node.js runtime and argv[1] is the provider CLI path
79		// (e.g. Gemini installed via npm: "node /home/linuxbrew/.linuxbrew/bin/gemini").
80		if base == "node" && len(parts) >= 2 {
81			if argBase := filepath.Base(parts[1]); argBase != "" && argBase != "." {
82				if _, ok := providerCLINames[argBase]; ok {
83					return argBase
84				}
85			}
86		}
87		return ""
88	}
89	
90	func providerRouteLabel(provider, model string) string {
91		route := strings.TrimSpace(provider)
92		if route != "" && strings.TrimSpace(model) != "" {
93			route += "/" + strings.TrimSpace(model)
94		}
95		return route
96	}
97	
98	func routeOwnsProvider(provider string, routeTokens ...string) bool {
99		p := strings.ToLower(strings.TrimSpace(provider))
100		if p == "" {
101			return false
102		}
103		for _, tok := range routeTokens {
104			tok = strings.ToLower(strings.TrimSpace(tok))
105			if tok == "" {
106				continue
107			}
108			if tok == p {
109				return true
110			}
111			if seg := strings.SplitN(tok, "/", 2); len(seg) > 0 && seg[0] == p {
112				return true
113			}
114		}
115		return false
116	}
117	
118	func scanProviderChildrenForStatus(ctx context.Context, rootPID int, routeLabel, harness, phase string, now time.Time) []workerstatus.ProviderChild {
119		procs, err := providerChildScanner(ctx, rootPID, now)
120		if err != nil || len(procs) == 0 {
121			return nil
122		}
123		activeOwner := activeRouteOwner(routeLabel, harness)
124		out := make([]workerstatus.ProviderChild, 0, len(procs))
125		for _, proc := range procs {
126			out = append(out, providerChildStatus(proc, routeLabel, harness, activeOwner, phase, now))
127		}
128		return out
129	}
130	
131	// providerChildStatus renders one scanned provider process as a status entry,
132	// marking it route-owned (RouteOwner set) or, when the active route is known
133	// and the provider does not match it, non-route with an operator-facing
134	// diagnostic. Non-route children observed without a known route are reported
135	// plain so an early scan never mislabels a child the guard cannot yet judge.
136	func providerChildStatus(proc providerChildProcess, routeLabel, harness, activeOwner, phase string, now time.Time) workerstatus.ProviderChild {
137		child := workerstatus.ProviderChild{
138			PID:        proc.PID,
139			Provider:   proc.Provider,
140			Harness:    proc.Provider,
141			Phase:      phase,
142			AgeSeconds: childAgeSeconds(proc, now),
143		}
144		if routeOwnsProvider(proc.Provider, routeLabel, harness) {
145			child.RouteOwner = activeOwner
146			return child
147		}
148		if activeOwner != "" {
149			child.NonRoute = true
150			child.Diagnostic = nonRouteProviderDiagnostic(proc.Provider, activeOwner)
151		}
152		return child
153	}
154	
155	// activeRouteOwner is the human-facing owner label for the active route:
156	// the route label when present, otherwise the harness. Empty when neither is
157	// known (route not yet resolved).
158	func activeRouteOwner(routeLabel, harness string) string {
159		if owner := strings.TrimSpace(routeLabel); owner != "" {
160			return owner
161		}
162		return strings.TrimSpace(harness)
163	}
164	
165	func nonRouteProviderDiagnostic(provider, owner string) string {
166		if owner == "" {
167			return "non-route provider " + provider + " terminated by running-phase guard"
168		}
169		return "non-route provider " + provider + " terminated by running-phase guard (active route " + owner + ")"
170	}
171	
172	// runningProviderChildGuard performs one running-phase sweep of the worker's
173	// provider-CLI descendants. Children whose provider matches the active
174	// route/harness are preserved and reported as route-owned; every other provider
175	// CLI is terminated by process group (taking grandchildren such as Gemini's
176	// Node worker with it) and reported as non-route with an operator-attention
177	// diagnostic. When the active route is not yet known (route and harness both
178	// empty) the guard observes without reaping, so it never quarantines a child it
179	// cannot yet attribute. Returns the status view and the reap evidence records.
180	func runningProviderChildGuard(ctx context.Context, rootPID int, routeLabel, harness, phase string, now time.Time) ([]workerstatus.ProviderChild, []providerChildReapRecord) {
181		procs, err := providerChildScanner(ctx, rootPID, now)
182		if err != nil || len(procs) == 0 {
183			return nil, nil
184		}
185		activeOwner := activeRouteOwner(routeLabel, harness)
186		children := make([]workerstatus.ProviderChild, 0, len(procs))
187		var reaped []providerChildReapRecord
188		for _, proc := range procs {
189			child := providerChildStatus(proc, routeLabel, harness, activeOwner, phase, now)
190			if child.NonRoute {
191				terminateProviderChild(proc.PID)
192				reaped = append(reaped, providerChildReapRecord{
193					PID:        proc.PID,
194					Provider:   proc.Provider,
195					Command:    proc.Command,
196					AgeSeconds: child.AgeSeconds,
197					Action:     providerChildActionTerminated,
198					Reason:     reasonRunningPhaseGuard,
199				})
200			}
201			children = append(children, child)
202		}
203		return children, reaped
204	}
205	
206	// runningProviderGuard is the attempt-scoped watchdog that drives
207	// runningProviderChildGuard on a ticker for the duration of attemptBackend.Run.
208	// It is owned by ExecuteBeadWithConfig (the shared ddx work / ddx try attempt
209	// path). The active route is seeded from any pinned harness/model and refreshed
210	// via UpdateRoute when fizeau resolves the route mid-attempt.
211	type runningProviderGuard struct {
212		projectRoot string
213		beadID      string
214		attemptID   string
215		rootPID     int
216		interval    time.Duration
217	
218		mu         sync.Mutex
219		routeLabel string
220		harness    string
221		reaped     []providerChildReapRecord
222	}
223	
224	func newRunningProviderGuard(projectRoot, beadID, attemptID string, rootPID int) *runningProviderGuard {
225		return &runningProviderGuard{
226			projectRoot: projectRoot,
227			beadID:      beadID,
228			attemptID:   attemptID,
229			rootPID:     rootPID,
230			interval:    runningProviderGuardInterval,
231		}
232	}
233	
234	// UpdateRoute records the active route. Non-empty harness/route values overwrite
235	// the prior values; empty values are ignored so a partial resolution never
236	// blanks a previously known route.
237	func (g *runningProviderGuard) UpdateRoute(harness, provider, model string) {
238		if g == nil {
239			return
240		}
241		g.mu.Lock()
242		defer g.mu.Unlock()
243		if h := strings.TrimSpace(harness); h != "" {
244			g.harness = h
245		}
246		if r := providerRouteLabel(provider, model); r != "" {
247			g.routeLabel = r
248		}
249	}
250	
251	func (g *runningProviderGuard) snapshotRoute() (string, string) {
252		g.mu.Lock()
253		defer g.mu.Unlock()
254		return g.routeLabel, g.harness
255	}
256	
257	// Reaped returns a copy of the running-phase reap evidence accumulated so far,
258	// so attempt-end cleanup can fold it into the final provider-children.json.
259	func (g *runningProviderGuard) Reaped() []providerChildReapRecord {
260		if g == nil {
261			return nil
262		}
263		g.mu.Lock()
264		defer g.mu.Unlock()
265		return append([]providerChildReapRecord(nil), g.reaped...)
266	}
267	
268	// Start launches the watchdog goroutine and returns a stop function. The stop
269	// function is idempotent and safe to call after ctx is already done.
270	func (g *runningProviderGuard) Start(ctx context.Context) func() {
271		if g == nil {
272			return func() {}
273		}
274		done := make(chan struct{})
275		var once sync.Once
276		go func() {
277			ticker := time.NewTicker(g.interval)
278			defer ticker.Stop()
279			for {
280				select {
281				case <-ctx.Done():
282					return
283				case <-done:
284					return
285				case t := <-ticker.C:
286					g.tick(ctx, t.UTC())
287				}
288			}
289		}()
290		return func() { once.Do(func() { close(done) }) }
291	}
292	
293	func (g *runningProviderGuard) tick(ctx context.Context, now time.Time) {
294		route, harness := g.snapshotRoute()
295		_, reaped := runningProviderChildGuard(ctx, g.rootPID, route, harness, "running", now)
296		if len(reaped) == 0 {
297			return
298		}
299		g.mu.Lock()
300		g.reaped = append(g.reaped, reaped...)
301		cumulative := append([]providerChildReapRecord(nil), g.reaped...)
302		g.mu.Unlock()
303		writeProviderChildCleanupArtifact(g.projectRoot, g.attemptID, &providerChildCleanupReport{
304			AttemptID:   g.attemptID,
305			BeadID:      g.beadID,
306			Trigger:     reasonRunningPhaseGuard,
307			ActiveRoute: activeRouteOwner(route, harness),
308			ScannedAt:   now,
309			Reaped:      cumulative,
310		})
311	}
312	
313	func reapProviderChildren(ctx context.Context, rootPID int, now time.Time, reasonFor func(providerChildProcess) string) ([]providerChildReapRecord, []workerstatus.ProviderChild, error) {
314		procs, err := providerChildScanner(ctx, rootPID, now)
315		if err != nil {
316			return nil, nil, err
317		}
318		var reaped []providerChildReapRecord
319		var survivors []workerstatus.ProviderChild
320		for _, proc := range procs {
321			reason := reasonFor(proc)
322			if reason == "" {
323				survivors = append(survivors, workerstatus.ProviderChild{
324					PID:        proc.PID,
325					Provider:   proc.Provider,
326					Harness:    proc.Provider,
327					AgeSeconds: childAgeSeconds(proc, now),
328				})
329				continue
330			}
331			terminateProviderChild(proc.PID)
332			reaped = append(reaped, providerChildReapRecord{
333				PID:        proc.PID,
334				Provider:   proc.Provider,
335				Command:    proc.Command,
336				AgeSeconds: childAgeSeconds(proc, now),
337				Action:     providerChildActionTerminated,
338				Reason:     reason,
339			})
340		}
341		return reaped, survivors, nil
342	}
343	
344	func reapSupersededProviderChildren(ctx context.Context, rootPID int, routeLabel, harness string, now time.Time) ([]providerChildReapRecord, []workerstatus.ProviderChild) {
345		if strings.TrimSpace(routeLabel) == "" && strings.TrimSpace(harness) == "" {
346			return nil, nil
347		}
348		reaped, survivors, err := reapProviderChildren(ctx, rootPID, now, func(proc providerChildProcess) string {
349			if routeOwnsProvider(proc.Provider, routeLabel, harness) {
350				return ""
351			}
352			return reasonSupersededProviderChild
353		})
354		if err != nil {
355			return nil, nil
356		}
357		return reaped, survivors
358	}
359	
360	func reapAllProviderChildren(ctx context.Context, rootPID int, now time.Time) []providerChildReapRecord {
361		reaped, _, err := reapProviderChildren(ctx, rootPID, now, func(providerChildProcess) string {
362			return reasonAttemptEnded
363		})
364		if err != nil {
365			return nil
366		}
367		return reaped
368	}
369	
370	func childAgeSeconds(proc providerChildProcess, now time.Time) float64 {
371		if proc.StartedAt.IsZero() {
372			return 0
373		}
374		age := now.Sub(proc.StartedAt)
375		if age < 0 {
376			return 0
377		}
378		return age.Seconds()
379	}
380	
381	func writeProviderChildCleanupArtifact(projectRoot, attemptID string, report *providerChildCleanupReport) {
382		if report == nil || strings.TrimSpace(projectRoot) == "" || strings.TrimSpace(attemptID) == "" {
383			return
384		}
385		path := filepath.Join(projectRoot, ExecuteBeadArtifactDir, attemptID, providerChildCleanupArtifact)
386		_ = writeArtifactJSON(path, report)
387	}
