3	package agent
4	
5	import (
6		"bytes"
7		"context"
8		"os"
9		"os/exec"
10		"strconv"
11		"strings"
12		"syscall"
13		"time"
14	)
15	
16	func scanProviderChildProcessesImpl(ctx context.Context, rootPID int, now time.Time) ([]providerChildProcess, error) {
17		cmd := exec.CommandContext(ctx, "ps", "-axo", "pid=,ppid=,etime=,command=")
18		out, err := cmd.Output()
19		if err != nil {
20			return nil, err
21		}
22		rows := parseProviderPS(out)
23		children := map[int][]int{}
24		row := map[int]providerPSRow{}
25		for _, r := range rows {
26			row[r.PID] = r
27			children[r.PPID] = append(children[r.PPID], r.PID)
28		}
29	
30		self := os.Getpid()
31		descendants := collectDescendants(children, rootPID)
32		out2 := make([]providerChildProcess, 0)
33		for pid := range descendants {
34			if pid == rootPID || pid == self || pid <= 0 {
35				continue
36			}
37			r, ok := row[pid]
38			if !ok {
39				continue
40			}
41			provider := providerForCommand(r.Command)
42			if provider == "" {
43				continue
44			}
45			started := time.Time{}
46			if r.ElapsedSeconds >= 0 {
47				started = now.Add(-time.Duration(r.ElapsedSeconds) * time.Second)
48			}
49			out2 = append(out2, providerChildProcess{
50				PID:       pid,
51				Provider:  provider,
52				Command:   r.Command,
53				StartedAt: started,
54			})
55		}
56		return out2, nil
57	}
58	
59	type providerPSRow struct {
60		PID            int
61		PPID           int
62		ElapsedSeconds int64
63		Command        string
64	}
65	
66	func parseProviderPS(out []byte) []providerPSRow {
67		lines := bytes.Split(out, []byte{'\n'})
68		rows := make([]providerPSRow, 0, len(lines))
69		for _, line := range lines {
70			fields := strings.Fields(string(line))
71			if len(fields) < 4 {
72				continue
73			}
74			pid, pidErr := strconv.Atoi(fields[0])
75			ppid, ppidErr := strconv.Atoi(fields[1])
76			if pidErr != nil || ppidErr != nil {
77				continue
78			}
79			rows = append(rows, providerPSRow{
80				PID:            pid,
81				PPID:           ppid,
82				ElapsedSeconds: parseEtime(fields[2]),
83				Command:        strings.Join(fields[3:], " "),
84			})
85		}
86		return rows
87	}
88	
89	func parseEtime(s string) int64 {
90		s = strings.TrimSpace(s)
91		if s == "" {
92			return -1
93		}
94		var days int64
95		if i := strings.Index(s, "-"); i >= 0 {
96			d, err := strconv.ParseInt(s[:i], 10, 64)
97			if err != nil {
98				return -1
99			}
100			days = d
101			s = s[i+1:]
102		}
103		parts := strings.Split(s, ":")
104		var h, m, sec int64
105		var err error
106		switch len(parts) {
107		case 3:
108			if h, err = strconv.ParseInt(parts[0], 10, 64); err != nil {
109				return -1
110			}
111			if m, err = strconv.ParseInt(parts[1], 10, 64); err != nil {
112				return -1
113			}
114			if sec, err = strconv.ParseInt(parts[2], 10, 64); err != nil {
115				return -1
116			}
117		case 2:
118			if m, err = strconv.ParseInt(parts[0], 10, 64); err != nil {
119				return -1
120			}
121			if sec, err = strconv.ParseInt(parts[1], 10, 64); err != nil {
122				return -1
123			}
124		default:
125			return -1
126		}
127		return days*86400 + h*3600 + m*60 + sec
128	}
129	
130	func collectDescendants(children map[int][]int, root int) map[int]struct{} {
131		out := map[int]struct{}{}
132		queue := []int{root}
133		for len(queue) > 0 {
134			pid := queue[0]
135			queue = queue[1:]
136			for _, child := range children[pid] {
137				if _, seen := out[child]; seen {
138					continue
139				}
140				out[child] = struct{}{}
141				queue = append(queue, child)
142			}
143		}
144		return out
145	}
146	
147	func terminateProviderChildImpl(pid int) {
148		if pid <= 0 || pid == os.Getpid() {
149			return
150		}
151		signalProviderChildGroup(pid, syscall.SIGTERM)
152		deadline := time.Now().Add(750 * time.Millisecond)
153		for time.Now().Before(deadline) {
154			if !signalProcessAlive(pid) {
155				return
156			}
157			time.Sleep(25 * time.Millisecond)
158		}
159		signalProviderChildGroup(pid, syscall.SIGKILL)
160	}
161	
162	func signalProviderChildGroup(pid int, sig syscall.Signal) {
163		if err := syscall.Kill(-pid, sig); err != nil && err != syscall.ESRCH {
164			_ = syscall.Kill(pid, sig)
165		}
166	}
