1603	// cleanupAttemptWorktree removes the per-attempt execute-bead worktree for
1604	// non-success outcomes unless the caller explicitly asked to preserve the
1605	// worktree for inspection. It returns true when it performed the removal.
1606	func cleanupAttemptWorktree(gitOps GitOps, workDir, wtPath, outcome string, preserveFlag bool) bool {
1607		if preserveFlag || outcome == ExecuteBeadOutcomeTaskSucceeded {
1608			return false
1609		}
1610		if gitOps == nil || workDir == "" || wtPath == "" {
1611			return false
1612		}
1613		_ = gitOps.WorktreeRemove(workDir, wtPath)
