1617	// preserveDirtyNoEvidenceAttempt stages all dirty files in the attempt
1618	// worktree, generates a binary patch of staged content, and writes it to the
1619	// artifact bundle directory so operators can recover the agent's uncommitted
1620	// work. Returns the bundle-relative path of the patch on success, or "" if
1621	// nothing was staged or the write failed. The patch survives worktree cleanup
1622	// because publishEvidenceBundleToProjectRoot copies the artifact dir to the
1623	// project root before cleanup runs.
1624	func preserveDirtyNoEvidenceAttempt(wtPath, artifactsDirAbs, artifactsDirRel string) string {
1625		// Use the same exclusion pathspecs as SynthesizeCommit so that DDx-managed
1626		// execution-bundle files (prompt.md, manifest.json, embedded/, etc.) are not
1627		// included in the rescue patch. If only those noise files are dirty, the
1628		// staging produces an empty index and we return "" (clean no-evidence).
1629		addArgs := append([]string{"add", "-A", "--", "."}, synthesizeCommitExcludePathspecs(wtPath)...)
1630		if err := internalgit.Command(context.Background(), wtPath, addArgs...).Run(); err != nil {
1631			return ""
1632		}
1633		patchData, err := internalgit.Command(context.Background(), wtPath, "diff", "--cached", "--binary").Output()
1634		if err != nil || len(bytes.TrimSpace(patchData)) == 0 {
1635			return ""
1636		}
1637		if err := os.MkdirAll(artifactsDirAbs, 0o755); err != nil {
1638			return ""
1639		}
1640		patchPath := filepath.Join(artifactsDirAbs, "dirty_rescue.patch")
1641		if err := os.WriteFile(patchPath, patchData, 0o644); err != nil {
1642			return ""
1643		}
1644		return filepath.ToSlash(filepath.Join(artifactsDirRel, "dirty_rescue.patch"))
1645	}
