1647	// commitTrackerLocked commits beads.jsonl if it has uncommitted changes.
1648	// Callers must hold withTrackerLock(projectRoot) before calling. Used by Run()
1649	// to fold tracker commit, checkpoint synthesis, and worktree creation into a
1650	// single critical section so concurrent workers do not race on the parent's
1651	// HEAD ref.
1652	func commitTrackerLocked(projectRoot string) error {
1653		trackerFile := filepath.Join(beadStoreRoot(projectRoot), "beads.jsonl")
1654		info, err := os.Stat(trackerFile)
1655		if err != nil {
1656			if os.IsNotExist(err) {
1657				return nil
1658			}
1659			return fmt.Errorf("checking tracker file: %w", err)
1660		}
1661		if info.IsDir() {
1662			return nil
1663		}
1664	
1665		gitDir, trackerPathspecs := ddxStateGitScope(projectRoot, ".ddx/beads.jsonl")
1666		trackerPathspec := trackerPathspecs[0]
1667	
1668		out, err := internalgit.Command(context.Background(), gitDir, "rev-parse", "--is-inside-work-tree").Output()
1669		if err != nil || strings.TrimSpace(string(out)) != "true" {
1670			return nil
1671		}
1672	
1673		msg := fmt.Sprintf("chore: update tracker (execute-bead %s)", time.Now().UTC().Format("20060102T150405"))
1674	
1675		// Re-check inside the lock: a sibling worker may have already
1676		// committed the tracker changes between our pre-lock check and now.
1677		diff, err := internalgit.Command(context.Background(), gitDir, "diff", "--", trackerPathspec).Output()
1678		if err != nil {
1679			return fmt.Errorf("checking tracker diff: %w", err)
1680		}
1681		if strings.TrimSpace(string(diff)) == "" {
1682			untracked, err := internalgit.Command(context.Background(), gitDir, "ls-files", "--others", "--exclude-standard", trackerPathspec).Output()
1683			if err != nil {
1684				return fmt.Errorf("checking tracker untracked: %w", err)
1685			}
1686			if strings.TrimSpace(string(untracked)) == "" {
1687				return nil
1688			}
1689		}
1690	
1691		commitOut, err := runGitWithIndexLockRecovery(context.Background(), gitDir, "add", trackerPathspec)
1692		if err != nil {
1693			return fmt.Errorf("staging tracker: %s: %w", strings.TrimSpace(string(commitOut)), err)
1694		}
1695		// `git commit` would fail with "nothing to commit" if the file's
1696		// content is byte-identical to HEAD even though `git diff` saw a
1697		// diff (e.g. mode/whitespace race). Bail cleanly in that case.
1698		if cached, err := internalgit.Command(context.Background(), gitDir, "diff", "--cached", "--", trackerPathspec).Output(); err == nil && strings.TrimSpace(string(cached)) == "" {
1699			return nil
1700		}
1701		commitArgs := ddxStateCommitArgs(projectRoot, gitDir, "commit", "--no-verify", "--only", "-m", msg, "--", trackerPathspec)
1702		commitOut, err = runGitWithIndexLockRecovery(context.Background(), gitDir, commitArgs...)

