240		shPath, err := exec.LookPath("sh")
241		if err != nil {
242			t.Skipf("sh not available: %v", err)
243		}
244		sleepPath, err := exec.LookPath("sleep")
245		if err != nil {
246			t.Skipf("sleep not available: %v", err)
247		}
248		dir := t.TempDir()
249		nodeBin := filepath.Join(dir, "node")
250		if err := os.Symlink(sleepPath, nodeBin); err != nil {
251			t.Fatalf("symlink fake node: %v", err)
252		}
253		geminiBin := filepath.Join(dir, "gemini")
254		if err := os.Symlink(shPath, geminiBin); err != nil {
255			t.Fatalf("symlink fake gemini: %v", err)
256		}
257		pidFile := filepath.Join(dir, "node.pid")
258	
259		// argv[0] is the gemini symlink path so the scanner classifies the parent as
260		// a "gemini" provider; the backgrounded fake node inherits gemini's process
261		// group (non-interactive sh keeps no separate group for background jobs), so
262		// it is a grandchild reachable only by killing the group.
263		cmd := exec.Command(geminiBin, "-c", `"$1" 120 & echo $! > "$2"; wait`, "gemini", nodeBin, pidFile)
264		cmd.SysProcAttr = &syscall.SysProcAttr{Setpgid: true}
265		if err := cmd.Start(); err != nil {
266			t.Fatalf("start fake gemini: %v", err)
267		}
268		geminiPID := cmd.Process.Pid
269		go func() { _, _ = cmd.Process.Wait() }()
270		t.Cleanup(func() { _ = syscall.Kill(-geminiPID, syscall.SIGKILL) })
271	
272		waitForProviderChildren(t, os.Getpid(), geminiPID)
273		nodePID := waitForPIDFile(t, pidFile)
274	
275		_, reaped := runningProviderChildGuard(context.Background(), os.Getpid(), "claude/sonnet", "", "running", time.Now().UTC())
276	
277		assertProcessGone(t, geminiPID)
278		assertProcessGone(t, nodePID)
279	
280		var sawGemini bool
281		for _, r := range reaped {
282			if r.Provider == "gemini" {
283				sawGemini = true
284			}
285		}
286		if !sawGemini {
287			t.Fatalf("running guard must reap the gemini parent; got %+v", reaped)
288		}
289	}
