388	func (r *providerChildRunner) Run(opts RunArgs) (*Result, error) {
389		cmd := exec.Command(r.bin, "120")
390		cmd.SysProcAttr = &syscall.SysProcAttr{Setpgid: true}
391		if err := cmd.Start(); err != nil {
392			return &Result{ExitCode: 1, Error: err.Error()}, nil
393		}
394		pid := cmd.Process.Pid
395		go func() { _, _ = cmd.Process.Wait() }()
396		r.started <- pid
397		switch r.mode {
398		case "interrupt":
399			ctx := opts.Context
400			if ctx == nil {
401				ctx = context.Background()
402			}
403			<-ctx.Done()
404			return &Result{ExitCode: 1, Error: ctx.Err().Error()}, nil
405		case "failure":
406			return &Result{ExitCode: 1, Error: "synthetic failure"}, nil
407		default:
408			return &Result{ExitCode: 0}, nil
409		}
410	}
