412	func waitForProviderChildren(t *testing.T, rootPID int, pids ...int) {
413		t.Helper()
414		deadline := time.Now().Add(3 * time.Second)
415		for time.Now().Before(deadline) {
416			procs, err := providerChildScanner(context.Background(), rootPID, time.Now().UTC())
417			if err == nil {
418				seen := map[int]bool{}
419				for _, p := range procs {
420					seen[p.PID] = true
421				}
422				all := true
423				for _, pid := range pids {
424					if !seen[pid] {
425						all = false
426						break
427					}
428				}
429				if all {
430					return
431				}
432			}
433			time.Sleep(25 * time.Millisecond)
434		}
435		t.Fatalf("scanner did not observe all provider children %v under pid %d", pids, rootPID)
436	}
