477		// retains the original argv (nodeBin, geminiScript) visible in ps.
478		geminiScript := filepath.Join(dir, "gemini")
479		if err := os.WriteFile(geminiScript, []byte("#!/bin/sh\nsleep 120\n"), 0755); err != nil {
480			t.Fatalf("write gemini script: %v", err)
481		}
482	
483		// nodeBin is the fake "node" path used as argv[0]; the actual binary run
484		// is sh so that the process blocks while ps shows "node /tmp/.../gemini".
485		nodeBin := filepath.Join(dir, "node")
