488		// as "/tmp/.../node /tmp/.../gemini" — the real-world Node-wrapper shape.
489		cmd := &exec.Cmd{
490			Path:        shPath,
491			Args:        []string{nodeBin, geminiScript},
492			SysProcAttr: &syscall.SysProcAttr{Setpgid: true},
