91	func (t *serverOutageTracker) Record(report ExecuteBeadReport, beadID string, now time.Time) (activated bool, reason string) {
92		if t == nil || t.active {
93			return false, ""
94		}
95		if isServerTransportFailureReport(report) {
96			t.Activate(now, FailureModeServerUnavailable)
97			return true, FailureModeServerUnavailable
98		}
99		if !isNoViableProviderReport(report) {
100			return false, ""
101		}
102		cutoff := now.Add(-t.window)
103		filtered := t.samples[:0]
104		distinct := make(map[string]struct{}, len(t.samples)+1)
105		for _, sample := range t.samples {
106			if sample.at.Before(cutoff) {
107				continue
108			}
109			filtered = append(filtered, sample)
110			if sample.beadID != "" {
111				distinct[sample.beadID] = struct{}{}
112			}
113		}
114		t.samples = append(filtered, serverOutageSample{beadID: beadID, at: now})
115		if beadID != "" {
116			distinct[beadID] = struct{}{}
117		}
118		if len(distinct) < t.threshold {
119			return false, ""
120		}
121		t.Activate(now, FailureModeServerUnavailable)
122		return true, FailureModeServerUnavailable
123	}
