139	func isServerTransportFailureReport(report ExecuteBeadReport) bool {
140		if strings.TrimSpace(report.Provider) != "" {
141			return false
142		}
143		combined := strings.ToLower(strings.Join([]string{
144			report.Detail,
145			report.Error,
146			report.Stderr,
147		}, "\n"))
148		return isServerTransportFailureText(combined)
149	}
150	
151	func isServerTransportFailureText(lower string) bool {
152		if lower == "" {
153			return false
154		}
155		if containsAny(lower,
156			"tls handshake error",
157			"remote error: tls: bad certificate",
158			"server closed idle connection",
159		) {
160			return true
161		}
162		return containsAny(lower, "unexpected eof") &&
163			containsAny(lower, "server", "api/health", "127.0.0.1", "localhost", "ddx")
164	}
