39	
40	// ProviderChild describes a provider CLI subprocess observed under a worker.
41	//
42	// RouteOwner is set when the child's provider matches the worker's active
43	// route/harness; such a child is legitimate route work and is never reaped.
44	// NonRoute is set on a provider CLI whose provider does not match the active
45	// route — an unrelated harness the running-phase guard terminates — and
46	// Diagnostic carries an operator-facing explanation for that quarantine.
47	type ProviderChild struct {
48		PID        int     `json:"pid"`
49		Provider   string  `json:"provider"`
50		Harness    string  `json:"harness,omitempty"`
51		RouteOwner string  `json:"route_owner,omitempty"`
