56	}
57	
58	// Scanner discovers live ddx worker processes on the host.
59	type Scanner interface {
60		Scan(ctx context.Context) ([]LiveWorker, error)
61	}
62	
63	// New returns the platform-appropriate Scanner. On Linux this reads /proc.
64	// On other platforms it returns an empty list; the caller's tests and the
65	// --all-projects escape hatch remain meaningful regardless.
66	func New() Scanner {
67		return newSystemScanner()
68	}
69	
70	// beadIDPattern matches ddx-style bead identifiers (prefix + hex, 8+ chars
71	// total) embedded in argv strings or worktree paths.
72	var beadIDPattern = regexp.MustCompile(`\bddx-[a-f0-9]{8}\b`)
73	
74	// executionWorktreePattern matches the conventional execute-bead worktree
75	// directory name (`.execute-bead-wt-<bead>-<timestamp>-<suffix>`) anywhere
76	// in a path. The directory name is enough to identify the worktree even when
77	// the surrounding path is unconventional.
78	var executionWorktreePattern = regexp.MustCompile(`(?:^|/)(\.execute-bead-wt-[^/]+)`)
79	
80	// InferBead extracts a bead ID and execution worktree path from the worker's
81	// command line and current working directory. It returns the longest worktree
82	// path that contains a `.execute-bead-wt-*` segment (typically the cwd, when
83	// the inline worker has chdir'd into the isolated worktree), and the first
84	// bead ID matched in either the command line or the worktree path.
85	//
86	// Either return value may be empty when no signal is present, which is the
87	// expected case for a long-running `ddx work` drain that has not yet started
88	// a specific bead.
89	func InferBead(cmdline, cwd string) (beadID, worktree string) {
90		worktree = extractWorktreePath(cwd)
91		if worktree == "" {
92			worktree = extractWorktreePath(cmdline)
93		}
94	
95		if m := beadIDPattern.FindString(worktree); m != "" {
96			beadID = m
97		}
98		if beadID == "" {
99			if m := beadIDPattern.FindString(cmdline); m != "" {
100				beadID = m
101			}
102		}
103		if beadID == "" {
104			if m := beadIDPattern.FindString(cwd); m != "" {
105				beadID = m
106			}
107		}
108		return beadID, worktree
109	}
110	
111	func extractWorktreePath(s string) string {
112		if s == "" {
113			return ""
114		}
115		if !strings.Contains(s, ".execute-bead-wt-") {
116			return ""
117		}
118		matches := executionWorktreePattern.FindStringIndex(s)
119		if matches == nil {
120			return ""
121		}
122		start := matches[0]
123		end := matches[1]
124		for start > 0 {
125			r := s[start-1]
126			if r == ' ' || r == '\x00' || r == '\t' {
127				break
128			}
129			start--
130		}
131		for end < len(s) {
132			r := s[end]
133			if r == ' ' || r == '\x00' || r == '\t' {
134				break
135			}
136			end++
137		}
138		return s[start:end]
139	}
140	
141	// FilterByProject returns workers whose ProjectRoot resolves to the same path
142	// as projectRoot. Resolution canonicalises both sides via filepath.Abs and
143	// filepath.EvalSymlinks so a symlinked checkout matches its real path.
144	func FilterByProject(workers []LiveWorker, projectRoot string) []LiveWorker {
145		target := canonicalPath(projectRoot)
146		out := make([]LiveWorker, 0, len(workers))
147		for _, w := range workers {
148			if SamePath(w.ProjectRoot, target) {
149				out = append(out, w)
150			}
151		}
152		return out
153	}
154	
155	// SamePath reports whether a and b refer to the same on-disk location after
156	// canonicalisation. It tolerates empty inputs (returning false) so callers
157	// can safely compare optional fields without prefiltering.
158	func SamePath(a, b string) bool {
159		ca := canonicalPath(a)
160		cb := canonicalPath(b)
161		if ca == "" || cb == "" {
162			return false
163		}
164		return ca == cb
165	}
166	
167	func canonicalPath(p string) string {
168		if strings.TrimSpace(p) == "" {
169			return ""
170		}
171		abs, err := filepath.Abs(p)
172		if err != nil {
173			abs = filepath.Clean(p)
174		}
175		if resolved, err := filepath.EvalSymlinks(abs); err == nil {
176			return resolved
177		}
178		return abs
179	}
180	
181	// FormatAge renders a duration as a short human-readable string mirroring
182	// the conventions used by the server-backed worker list (`5s`, `12m`,
183	// `1h30m`). It is intended for terminal output; JSON output uses
184	// AgeSeconds as the numeric source of truth.
185	func FormatAge(d time.Duration) string {
186		if d < time.Minute {
187			if d < 0 {
188				d = 0
189			}
190			return roundedSeconds(d)
191		}
192		if d < time.Hour {
193			return roundedMinutes(d)
194		}
195		hours := int(d.Hours())
196		mins := int(d.Minutes()) % 60
197		if mins == 0 {
198			return durationHours(hours)
199		}
200		return durationHoursMinutes(hours, mins)
201	}
202	
203	func roundedSeconds(d time.Duration) string {
204		secs := int(d.Seconds())
205		return durationSeconds(secs)
206	}
207	
