40	// LivenessTTL is the freshness window for treating a worker sidecar as
41	// "active". Defaults to 3× the bead tracker heartbeat interval (which is
42	// 30s) so a sidecar that has not been touched in ~90s is treated as stale.
43	var LivenessTTL = 90 * time.Second
44	
45	// LivenessDir returns the worker sidecar directory for a project.
46	func LivenessDir(projectRoot string) string {
47		inTree := ddxroot.InTree(projectRoot)
48		if info, err := os.Stat(inTree); err == nil && info.IsDir() {
49			return filepath.Join(inTree, "workers")
50		}
51		return ddxroot.JoinProject(projectRoot, "workers")
52	}
53	
54	// LivenessPath returns the status.json path for a worker under projectRoot.
55	func LivenessPath(projectRoot, workerID string) string {
56		return filepath.Join(LivenessDir(projectRoot), workerID, "status.json")
57	}
58	
59	// WriteLiveness writes rec to .ddx/workers/<workerID>/status.json using a
60	// tmp-then-rename so concurrent readers never see a half-written file.
61	func WriteLiveness(projectRoot, workerID string, rec LivenessRecord) error {
62		if projectRoot == "" || workerID == "" {
63			return fmt.Errorf("workerstatus: project root and worker id required")
64		}
65		dir := filepath.Join(LivenessDir(projectRoot), workerID)
66		if err := os.MkdirAll(dir, 0o755); err != nil {
67			return fmt.Errorf("workerstatus: mkdir worker dir: %w", err)
68		}
69		data, err := json.MarshalIndent(rec, "", "  ")
70		if err != nil {
71			return fmt.Errorf("workerstatus: marshal liveness: %w", err)
72		}
73		data = append(data, '\n')
74		final := filepath.Join(dir, "status.json")
75		tmp, err := os.CreateTemp(dir, "status-*.tmp")
76		if err != nil {
77			return fmt.Errorf("workerstatus: create tmp: %w", err)
78		}
79		tmpName := tmp.Name()
80		if _, err := tmp.Write(data); err != nil {
81			_ = tmp.Close()
82			_ = os.Remove(tmpName)
83			return fmt.Errorf("workerstatus: write tmp: %w", err)
84		}
85		if err := tmp.Close(); err != nil {
86			_ = os.Remove(tmpName)
87			return fmt.Errorf("workerstatus: close tmp: %w", err)
88		}
89		if err := os.Rename(tmpName, final); err != nil {
90			_ = os.Remove(tmpName)
91			return fmt.Errorf("workerstatus: rename: %w", err)
92		}
93		return nil
94	}
95	
96	// ReadLiveness reads the sidecar for workerID under projectRoot.
97	func ReadLiveness(projectRoot, workerID string) (LivenessRecord, error) {
98		var rec LivenessRecord
99		data, err := os.ReadFile(LivenessPath(projectRoot, workerID))
100		if err != nil {
101			return rec, err
102		}
103		if err := json.Unmarshal(data, &rec); err != nil {
104			return rec, fmt.Errorf("workerstatus: parse liveness: %w", err)
105		}
106		return rec, nil
107	}
108	
109	// ListLiveness reads every status.json sidecar under projectRoot's worker
110	// directory. Malformed sidecars are skipped silently — the sidecar is
111	// best-effort observability, not authoritative state.
112	func ListLiveness(projectRoot string) ([]LivenessRecord, error) {
113		dir := LivenessDir(projectRoot)
114		entries, err := os.ReadDir(dir)
115		if err != nil {
116			if os.IsNotExist(err) {
117				return nil, nil
118			}
119			return nil, err
120		}
121		var out []LivenessRecord
122		for _, entry := range entries {
123			if !entry.IsDir() {
124				continue
125			}
126			rec, err := ReadLiveness(projectRoot, entry.Name())
127			if err != nil {
128				continue
129			}
130			out = append(out, rec)
131		}
132		sort.Slice(out, func(i, j int) bool {
133			return out[i].LastActivityAt.After(out[j].LastActivityAt)
134		})
135		return out, nil
136	}
137	
138	// IsFresh reports whether rec.LastActivityAt is within LivenessTTL of now.
139	func (r LivenessRecord) IsFresh(now time.Time) bool {
140		if r.LastActivityAt.IsZero() {
141			return false
142		}
143		return now.Sub(r.LastActivityAt) <= LivenessTTL
144	}
