// routeChildAlive reports whether children contains a live route-owned provider
// subprocess (RouteOwner set and not flagged non-route).
func routeChildAlive(children []workerstatus.ProviderChild) bool {
	for _, c := range children {
		if strings.TrimSpace(c.RouteOwner) != "" && !c.NonRoute {
			return true
		}
	}
	return false
}

// observeRouteChild records one heartbeat snapshot and reports whether a
// previously-observed route-owned provider subprocess has now been absent for
// at least grace while the attempt is still in the running phase. It latches
// routeChildSeen on the first live observation, so a harness that never spawns
// a provider subprocess (an in-process/API route) never fires. A grace of zero
// disables the detector.
func (w *progressWatchdog) observeRouteChild(now time.Time, phase string, children []workerstatus.ProviderChild, grace time.Duration) bool {
	if grace <= 0 {
		return false
	}
	if routeChildAlive(children) {
		w.routeChildSeen = true
		w.routeChildGoneSince = time.Time{}
		return false
	}
	if !w.routeChildSeen || phase != string(PhaseRunning) {
		return false
	}
	if w.routeChildGoneSince.IsZero() {
		w.routeChildGoneSince = now
	}
	return now.Sub(w.routeChildGoneSince) >= grace
}

