func (g *runningProviderGuard) tick(ctx context.Context, now time.Time) {
	route, harness := g.snapshotRoute()
	_, reaped := runningProviderChildGuard(ctx, g.rootPID, route, harness, "running", now)
	if len(reaped) == 0 {
		// No non-route child observed this tick: any prior survivor is now
		// confirmed gone, so reset the survivor set.
		g.mu.Lock()
		g.survivors = nil
		g.mu.Unlock()
		return
	}
	// Escalate any non-route child that survived a prior reap attempt: a PID
	// still present after we already signalled it means the reap did not stick
	// or the child keeps respawning. Hard-kill the process group again and log
	// at ERROR so the churn is visible instead of silently looping.
	g.escalateSurvivors(reaped)
	g.mu.Lock()
	g.reaped = append(g.reaped, reaped...)
	cumulative := append([]providerChildReapRecord(nil), g.reaped...)
	g.mu.Unlock()

// escalateSurvivors compares the children reaped this tick against the set the
// guard already tried to reap on the previous tick. A PID present in both means
// the earlier SIGTERM/SIGKILL did not stick (or the child respawned under the
// same PID): the scanner only reports live processes, so its reappearance is
// itself proof it survived. The guard hard-kills it again via terminateProviderChild
// (SIGTERM→SIGKILL by process group) and logs at ERROR so the churn is visible.
// It then records this tick's reaped PIDs as the next survivor-check set.
func (g *runningProviderGuard) escalateSurvivors(reaped []providerChildReapRecord) {
	g.mu.Lock()
	prev := g.survivors
	logf := g.logf
	current := make(map[int]struct{}, len(reaped))
	var escalate []providerChildReapRecord
	for _, rec := range reaped {
		current[rec.PID] = struct{}{}
		if prev != nil {
			if _, ok := prev[rec.PID]; ok {
				escalate = append(escalate, rec)
			}
		}
	}
	g.survivors = current
	g.mu.Unlock()

	for _, rec := range escalate {
		if logf != nil {
			logf("ERROR: non-route provider %s pid %d survived running-phase guard reap; hard-killing (bead %s attempt %s)",
				rec.Provider, rec.PID, g.beadID, g.attemptID)
		}
		terminateProviderChild(rec.PID)
	}
}

