// TestProgressWatchdogObserveRouteChildDeath verifies the route-subprocess
// death detector: it latches once a route-owned provider child is seen alive,
// then fires only after that child has been absent for the grace window while
// the attempt is still running. A harness that never spawns a provider child
// must never fire.
func TestProgressWatchdogObserveRouteChildDeath(t *testing.T) {
	base := time.Date(2026, 7, 2, 12, 0, 0, 0, time.UTC)
	live := []workerstatus.ProviderChild{{PID: 111, Provider: "claude", RouteOwner: "claude/opus"}}
	nonRouteOnly := []workerstatus.ProviderChild{{PID: 222, Provider: "codex", NonRoute: true}}

	t.Run("fires after grace once route child disappears", func(t *testing.T) {
		wd := &progressWatchdog{}
		grace := 20 * time.Second
		// Route child alive: latches routeChildSeen, never fires.
		require.False(t, wd.observeRouteChild(base, string(PhaseRunning), live, grace))
		// Child gone: arms the timer but within grace, does not fire.
		require.False(t, wd.observeRouteChild(base.Add(5*time.Second), string(PhaseRunning), nonRouteOnly, grace))
		// Still gone, still within grace.
		require.False(t, wd.observeRouteChild(base.Add(10*time.Second), string(PhaseRunning), nil, grace))
		// Past grace from the first-gone observation: fires.
		require.True(t, wd.observeRouteChild(base.Add(25*time.Second), string(PhaseRunning), nil, grace))
	})

	t.Run("never fires when route child never observed", func(t *testing.T) {
		wd := &progressWatchdog{}
		grace := time.Second
		// Only a non-route child was ever seen — an in-process/API route that
		// spawns no provider subprocess must not be treated as a death.
		require.False(t, wd.observeRouteChild(base, string(PhaseRunning), nonRouteOnly, grace))
		require.False(t, wd.observeRouteChild(base.Add(time.Hour), string(PhaseRunning), nil, grace))
	})

	t.Run("re-arms when route child returns", func(t *testing.T) {
		wd := &progressWatchdog{}
		grace := 20 * time.Second
		require.False(t, wd.observeRouteChild(base, string(PhaseRunning), live, grace))
		require.False(t, wd.observeRouteChild(base.Add(5*time.Second), string(PhaseRunning), nil, grace))
		// Route child reappears (transient scan miss): timer resets.
		require.False(t, wd.observeRouteChild(base.Add(10*time.Second), string(PhaseRunning), live, grace))
		// Well past the original gone time, but the timer restarted.
		require.False(t, wd.observeRouteChild(base.Add(20*time.Second), string(PhaseRunning), nil, grace))
	})

	t.Run("disabled when grace is zero", func(t *testing.T) {
		wd := &progressWatchdog{}
		require.False(t, wd.observeRouteChild(base, string(PhaseRunning), live, 0))
		require.False(t, wd.observeRouteChild(base.Add(time.Hour), string(PhaseRunning), nil, 0))
	})
}

// TestRunProgressWatchdogFiresOnRouteChildDeath drives snapshots through the
// runner: a route-owned child observed alive then gone must trigger
// OnRouteChildDied exactly once (and not OnWedged).
func TestRunProgressWatchdogFiresOnRouteChildDeath(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	tickCh := make(chan time.Time)
	base := time.Date(2026, 7, 2, 12, 0, 0, 0, time.UTC)
	var clockNanos atomic.Int64
	clockNanos.Store(base.UnixNano())
	nowFn := func() time.Time { return time.Unix(0, clockNanos.Load()).UTC() }

	var children atomic.Value // []workerstatus.ProviderChild
	children.Store([]workerstatus.ProviderChild{{PID: 111, Provider: "claude", RouteOwner: "claude/opus"}})

	var wedgedCount, deathCount int
	var deathRec workerstatus.LivenessRecord
	done := make(chan struct{})
	go func() {
		runProgressWatchdog(ctx, tickCh, ProgressWatchdogConfig{
			Budgets:         PhaseBudgets{Resolving: time.Hour, Running: time.Hour},
			RouteChildGrace: 20 * time.Second,
			Now:             nowFn,
			Snapshot: func() workerstatus.LivenessRecord {
				return workerstatus.LivenessRecord{
					CurrentBead:      "ddx-routedeath",
					AttemptID:        "att-routedeath-001",
					Phase:            string(PhaseRunning),
					Route:            "claude/opus",
					Harness:          "claude",
					ProviderChildren: children.Load().([]workerstatus.ProviderChild),
					LastActivityAt:   nowFn(),
				}
			},
			OnWedged:         func(workerstatus.LivenessRecord, time.Duration) { wedgedCount++ },
			OnRouteChildDied: func(rec workerstatus.LivenessRecord) { deathCount++; deathRec = rec },
		})
		close(done)
	}()

	// Tick 1: route child alive — latches, no fire.
	tickCh <- nowFn()
	// Route subprocess dies: only a non-route child remains.
	children.Store([]workerstatus.ProviderChild{{PID: 222, Provider: "codex", NonRoute: true}})
	// Tick 2: child gone, arms the timer.
	clockNanos.Store(base.Add(time.Second).UnixNano())
	tickCh <- nowFn()
	// Tick 3: past grace — must fire OnRouteChildDied.
	clockNanos.Store(base.Add(30 * time.Second).UnixNano())
	tickCh <- nowFn()

	select {
	case <-done:
	case <-time.After(2 * time.Second):
		t.Fatal("route-child death watchdog did not fire when the route subprocess disappeared")
	}

	assert.Equal(t, 1, deathCount, "OnRouteChildDied must fire exactly once")
	assert.Equal(t, 0, wedgedCount, "the phase-empty wedge must not fire for a route-subprocess death")
	assert.Equal(t, "ddx-routedeath", deathRec.CurrentBead)
	assert.Equal(t, "claude/opus", deathRec.Route)
}

