// TestRunProgressWatchdogFiresOnRouteChildDeath drives snapshots through the
// runner: a route-owned child observed alive then gone must trigger
// OnRouteChildDied exactly once (and not OnWedged). The snapshot itself advances
// the injected clock per call so the observed time is deterministic regardless
// of goroutine scheduling.
func TestRunProgressWatchdogFiresOnRouteChildDeath(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	// Buffered so the three sends never block, even after the runner returns.
	tickCh := make(chan time.Time, 3)
	base := time.Date(2026, 7, 2, 12, 0, 0, 0, time.UTC)
	var clockNanos atomic.Int64
	clockNanos.Store(base.UnixNano())
	nowFn := func() time.Time { return time.Unix(0, clockNanos.Load()).UTC() }

	live := []workerstatus.ProviderChild{{PID: 111, Provider: "claude", RouteOwner: "claude/opus"}}
	nonRoute := []workerstatus.ProviderChild{{PID: 222, Provider: "codex", NonRoute: true}}

	var snapCount atomic.Int64
	var wedgedCount, deathCount int
	var deathRec workerstatus.LivenessRecord
	done := make(chan struct{})
	go func() {
		runProgressWatchdog(ctx, tickCh, ProgressWatchdogConfig{
			Budgets:         PhaseBudgets{Resolving: time.Hour, Running: time.Hour},
			RouteChildGrace: 20 * time.Second,
			Now:             nowFn,
			Snapshot: func() workerstatus.LivenessRecord {
				kids := nonRoute
				switch snapCount.Add(1) {
				case 1: // route child alive at t0
					kids = live
					clockNanos.Store(base.UnixNano())
				case 2: // route child gone, arm the timer at t0+1s
					clockNanos.Store(base.Add(time.Second).UnixNano())
				default: // still gone, past the grace window
					clockNanos.Store(base.Add(30 * time.Second).UnixNano())
				}
				return workerstatus.LivenessRecord{
					CurrentBead:      "ddx-routedeath",
					AttemptID:        "att-routedeath-001",
					Phase:            string(PhaseRunning),
					Route:            "claude/opus",
					Harness:          "claude",
					ProviderChildren: kids,
					LastActivityAt:   nowFn(),
				}
			},
			OnWedged:         func(workerstatus.LivenessRecord, time.Duration) { wedgedCount++ },
			OnRouteChildDied: func(rec workerstatus.LivenessRecord) { deathCount++; deathRec = rec },
		})
		close(done)
	}()

	tickCh <- base
	tickCh <- base
	tickCh <- base

	select {
	case <-done:
	case <-time.After(2 * time.Second):
		t.Fatal("route-child death watchdog did not fire when the route subprocess disappeared")
	}

	assert.Equal(t, 1, deathCount, "OnRouteChildDied must fire exactly once")
	assert.Equal(t, 0, wedgedCount, "the phase-empty wedge must not fire for a route-subprocess death")
	assert.Equal(t, "ddx-routedeath", deathRec.CurrentBead)
	assert.Equal(t, "claude/opus", deathRec.Route)
}

