// TestWork_NonRouteProviderIsActuallyReaped proves the running-phase guard's
// ticker actually terminates a non-route provider subprocess (via the real
// syscall.Kill + wait in terminateProviderChildImpl) within 10s while the
// active route is claude, that the route-owned claude child is preserved, and
// that the reaped child does not come back (ddx-f2b7cf89 root cause #1: the
// guard must reap, not merely label).
func TestWork_NonRouteProviderIsActuallyReaped(t *testing.T) {
	dir := t.TempDir()
	claudePID := startFakeProviderChild(t, dir, "claude") // active route
	codexPID := startFakeProviderChild(t, dir, "codex")   // non-route churn
	waitForProviderChildren(t, os.Getpid(), claudePID, codexPID)

	guard := newRunningProviderGuard(t.TempDir(), "ddx-reap", "att-reap", os.Getpid())
	guard.UpdateRoute("claude", "", "sonnet")
	guard.interval = 50 * time.Millisecond

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	stop := guard.Start(ctx)
	defer stop()

	// The non-route codex must actually be killed (assertProcessGone polls up
	// to 3s — comfortably inside the 10s bound).
	assertProcessGone(t, codexPID)
	// The active-route claude child must survive the guard.
	require.True(t, signalProcessAlive(claudePID), "active-route claude child must not be reaped")

	// It must not respawn: the codex PID stays dead and no live codex child is
	// observed on a fresh scan after several more guard ticks.
	time.Sleep(300 * time.Millisecond)
	require.False(t, signalProcessAlive(codexPID), "reaped non-route child must stay dead (no respawn)")
	procs, err := providerChildScanner(context.Background(), os.Getpid(), time.Now().UTC())
	require.NoError(t, err)
	for _, p := range procs {
		require.NotEqualf(t, "codex", p.Provider, "no codex provider child may reappear after reap: %+v", p)
	}

	reaped := guard.Reaped()
	var sawCodex bool
	for _, r := range reaped {
		if r.Provider == "codex" {
			sawCodex = true
			require.Equal(t, providerChildActionTerminated, r.Action)
			require.Equal(t, reasonRunningPhaseGuard, r.Reason)
		}
		require.NotEqual(t, "claude", r.Provider, "the active-route claude child must never appear in reap evidence")
	}
	require.True(t, sawCodex, "guard reap evidence must record the codex termination: %+v", reaped)
}

// TestRunningProviderGuardEscalatesSurvivingNonRouteChild proves the
// repeat-survivor escalation (ddx-f2b7cf89 fix #2): a non-route child that
// reappears on a later tick — the SIGKILL did not stick or it keeps respawning
// under the same PID — is hard-killed again and logged at ERROR, instead of the
// guard silently spinning.
func TestRunningProviderGuardEscalatesSurvivingNonRouteChild(t *testing.T) {
	const survivorPID = 727272
	now := time.Now().UTC()

	restoreScanner := providerChildScanner
	restoreTerminate := terminateProviderChild
	t.Cleanup(func() {
		providerChildScanner = restoreScanner
		terminateProviderChild = restoreTerminate
	})

	// The scanner keeps reporting the same non-route codex PID as live: the
	// reap never sticks (the classic wedge that fed the spawn-loop).
	providerChildScanner = func(context.Context, int, time.Time) ([]providerChildProcess, error) {
		return []providerChildProcess{{
			PID:       survivorPID,
			Provider:  "codex",
			Command:   "/usr/local/bin/codex",
			StartedAt: now.Add(-30 * time.Second),
		}}, nil
	}
	var mu sync.Mutex
	var killCount int
	terminateProviderChild = func(int) {
		mu.Lock()
		killCount++
		mu.Unlock()
	}

	var logMu sync.Mutex
	var escalationLogs []string
	guard := newRunningProviderGuard(t.TempDir(), "ddx-escalate", "att-escalate", os.Getpid())
	guard.UpdateRoute("claude", "", "sonnet")
	guard.SetEscalationLogger(func(format string, args ...any) {
		logMu.Lock()
		escalationLogs = append(escalationLogs, format)
		logMu.Unlock()
	})

	// First tick: reaps the codex (attempted kill), records it as a survivor
	// candidate but does not escalate yet.
	guard.tick(context.Background(), now)
	logMu.Lock()
	require.Empty(t, escalationLogs, "first observation must not escalate")
	logMu.Unlock()

	// Second tick: the same PID is still live => escalate with hard-kill + ERROR log.
	guard.tick(context.Background(), now.Add(2*time.Second))

	logMu.Lock()
	defer logMu.Unlock()
	require.Len(t, escalationLogs, 1, "a surviving non-route child must escalate exactly once per re-observation")
	require.Contains(t, escalationLogs[0], "ERROR")
	require.Contains(t, escalationLogs[0], "survived running-phase guard reap")

	mu.Lock()
	defer mu.Unlock()
	// Two reap ticks (one kill each) + one escalation hard-kill.
	require.GreaterOrEqual(t, killCount, 3, "the survivor must be hard-killed again on escalation")
}

// TestWork_ClaudeSubprocessDeathSynthesizesTerminalOutcome proves that when the
// route harness subprocess (claude) disappears mid-attempt without emitting a
// terminal event and the dispatch would otherwise hang in phase=running
// forever, the worker synthesizes an execution_failed outcome and writes a
// terminal worker.heartbeat with phase != "running" (ddx-f2b7cf89 fix #3).
func TestWork_ClaudeSubprocessDeathSynthesizesTerminalOutcome(t *testing.T) {
	projectRoot := t.TempDir()
	store := bead.NewStore(ddxroot.JoinProject(projectRoot))
	require.NoError(t, store.Init(context.Background()))
	require.NoError(t, store.Create(context.Background(), &bead.Bead{ID: "ddx-claudedeath1", Title: "route subprocess death"}))

	// The child probe sees a live route-owned claude subprocess for the first
	// few heartbeats, then it "dies" (scanner returns nothing) — the route
	// fields stay populated so the phase-empty wedge never fires.
	restoreScanner := providerChildScanner
	t.Cleanup(func() { providerChildScanner = restoreScanner })
	var probeCalls atomic.Int32
	providerChildScanner = func(_ context.Context, _ int, now time.Time) ([]providerChildProcess, error) {
		if probeCalls.Add(1) <= 3 {
			return []providerChildProcess{{
				PID:       990011,
				Provider:  "claude",
				Command:   "claude --print --model opus",
				StartedAt: now.Add(-2 * time.Second),
			}}, nil
		}
		return nil, nil
	}

	// The dispatch hangs until the route-death watchdog cancels the attempt,
	// mirroring a fizeau read that never returns because the dead subprocess
	// left a pipe open.
	var once sync.Once
	started := make(chan struct{})
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			once.Do(func() { close(started) })
			<-ctx.Done()
			return ExecuteBeadReport{
				BeadID: beadID,
				Status: ExecuteBeadStatusExecutionFailed,
				Error:  ctx.Err().Error(),
			}, nil
		}),
	}

	var sink lockedBuffer
	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker", Harness: "claude", Model: "opus", HeartbeatInterval: 20 * time.Millisecond}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer cancel()
	runErr := make(chan error, 1)
	go func() {
		_, err := worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{
			Mode:         executeloop.ModeWatch,
			IdleInterval: 20 * time.Millisecond,
			EventSink:    &sink,
			ProjectRoot:  projectRoot,
			SessionID:    "sess-claudedeath",
			WorkerID:     "worker-claudedeath",
		})
		runErr <- err
	}()

	select {
	case <-started:
	case <-time.After(15 * time.Second):
		t.Fatal("executor never started")
	}

	// Within the 30s bound the watchdog must fire, cancel the dispatch, and the
	// loop must emit both the route-death event and a terminal (phase!=running)
	// heartbeat.
	require.Eventually(t, func() bool {
		return strings.Contains(sink.String(), "loop.route_child_died") &&
			hasTerminalHeartbeat(sink.String())
	}, 25*time.Second, 20*time.Millisecond, "worker must synthesize a terminal outcome after route-subprocess death; sink=%s", sink.String())

	cancel()
	<-runErr

	assert.Contains(t, sink.String(), "\"status\":\""+ExecuteBeadStatusExecutionFailed+"\"",
		"a bead.result with execution_failed must be recorded")
	assert.Contains(t, sink.String(), disruptionReasonRouteChildDied,
		"the disruption must be classified as a route-subprocess death")
}

// TestWork_ClaudeSubprocessKilledMidAttemptExitsWithin60s is the scripted
// end-to-end guard for ddx-f2b7cf89 AC #3: a real claude subprocess is killed
// mid-attempt and the worker must exit the attempt (route-death watchdog fires,
// dispatch is cancelled, terminal heartbeat written) rather than wedging in
// phase=running with churning non-route children forever.
func TestWork_ClaudeSubprocessKilledMidAttemptExitsWithin60s(t *testing.T) {
	projectRoot := t.TempDir()
	store := bead.NewStore(ddxroot.JoinProject(projectRoot))
	require.NoError(t, store.Init(context.Background()))
	require.NoError(t, store.Create(context.Background(), &bead.Bead{ID: "ddx-claudekill1", Title: "kill claude mid-attempt"}))

	sleepPath, err := exec.LookPath("sleep")
	if err != nil {
		t.Skipf("sleep not available: %v", err)
	}
	binDir := t.TempDir()
	claudeBin := filepath.Join(binDir, "claude")
	require.NoError(t, os.Symlink(sleepPath, claudeBin))

	claudePIDCh := make(chan int, 1)
	var once sync.Once
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			// Spawn a real "claude" subprocess under the worker process. The
			// running-phase child probe will observe it as the route owner.
			cmd := exec.Command(claudeBin, "600")
			cmd.SysProcAttr = &syscall.SysProcAttr{Setpgid: true}
			if startErr := cmd.Start(); startErr != nil {
				return ExecuteBeadReport{ExitCode: 1, Error: startErr.Error()}, nil
			}
			pid := cmd.Process.Pid
			go func() { _, _ = cmd.Process.Wait() }()
			t.Cleanup(func() { _ = syscall.Kill(-pid, syscall.SIGKILL) })
			once.Do(func() { claudePIDCh <- pid })
			// Block as if reading from a pipe the dead subprocess left open.
			<-ctx.Done()
			return ExecuteBeadReport{BeadID: beadID, Status: ExecuteBeadStatusExecutionFailed, Error: ctx.Err().Error()}, nil
		}),
	}

	var sink lockedBuffer
	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker", Harness: "claude", Model: "sonnet", HeartbeatInterval: 100 * time.Millisecond}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	ctx, cancel := context.WithTimeout(context.Background(), 90*time.Second)
	defer cancel()
	runErr := make(chan error, 1)
	go func() {
		_, err := worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{
			Mode:         executeloop.ModeWatch,
			IdleInterval: 50 * time.Millisecond,
			EventSink:    &sink,
			ProjectRoot:  projectRoot,
			SessionID:    "sess-claudekill",
			WorkerID:     "worker-claudekill",
		})
		runErr <- err
	}()

	var claudePID int
	select {
	case claudePID = <-claudePIDCh:
	case <-time.After(30 * time.Second):
		t.Fatal("claude subprocess never started")
	}

	// Let the child probe observe the live route subprocess, then kill it
	// mid-attempt — the silent death the bead reproduces.
	waitForProviderChildren(t, os.Getpid(), claudePID)
	require.NoError(t, syscall.Kill(claudePID, syscall.SIGKILL))

	start := time.Now()
	require.Eventually(t, func() bool {
		return strings.Contains(sink.String(), "loop.route_child_died") && hasTerminalHeartbeat(sink.String())
	}, 60*time.Second, 100*time.Millisecond, "worker must exit the attempt within 60s of the claude subprocess dying")
	require.Less(t, time.Since(start), 60*time.Second)

	cancel()
	<-runErr
}

// hasTerminalHeartbeat reports whether the event stream contains a
// worker.heartbeat envelope whose phase is not "running" — the terminal
// heartbeat written once the attempt is cleared.
func hasTerminalHeartbeat(eventStream string) bool {
	for _, line := range strings.Split(eventStream, "\n") {
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}
		var entry struct {
			Type string `json:"type"`
			Data struct {
				Phase string `json:"phase"`
			} `json:"data"`
		}
		if err := json.Unmarshal([]byte(line), &entry); err != nil {
			continue
		}
		if entry.Type == "worker.heartbeat" && entry.Data.Phase != "running" {
			return true
		}
	}
	return false
}

