// Start launches the watchdog goroutine and returns a stop function. The stop
// function is idempotent and blocks until the goroutine has fully exited (any
// in-flight tick has returned), so callers can rely on no further provider
// scans or reaps racing after stop() returns. Safe to call after ctx is
// already done.
func (g *runningProviderGuard) Start(ctx context.Context) func() {
	if g == nil {
		return func() {}
	}
	done := make(chan struct{})
	stopped := make(chan struct{})
	var once sync.Once
	go func() {
		defer close(stopped)
		ticker := time.NewTicker(g.interval)
		defer ticker.Stop()
		for {
			select {
			case <-ctx.Done():
				return
			case <-done:
				return
			case t := <-ticker.C:
				g.tick(ctx, t.UTC())
			}
		}
	}()
	return func() {
		once.Do(func() { close(done) })
		<-stopped
	}
}

